import React from 'react';
import Image from 'next/image';

function AppImage({
  src,
  alt = "Image Name",
  className = "",
  width,
  height,
  ...props
}) {
  return (
    <Image
      src={src}
      alt={alt}
      className={className}
      width={width || 400}
      height={height || 300}
      placeholder="blur"
      blurDataURL="data:image/jpeg;base64,"
      onError={(e) => {
        e.target.src = "/assets/images/no_image.png"
      }}
      {...props}
    />
  );
}

export default AppImage;
